THE RISK:
{
 "id": "fragmented-incumbency-price-response",
 "title": "Five-to-seven co-equal incumbents plus an import price floor turn every entrant win into a contested knife-fight, pinning Year-1 pace to the band floor",
 "narrative": "shape.cr3's 0.55 is extrapolated from a single 15.8% Schneider datapoint; the actual evidence shows five to seven co-equal 'leading' vendors (Schneider, Eaton, Vertiv, ABB, Legrand, Siemens, nVent) and only qualitative 'medium/semi-consolidated' labels, with 60–70% import dependence in Eastern Europe setting a low-cost price floor. That structure is worse for an entrant than a tight oligopoly: more scaled players able and motivated to price-match any pilot win inside their accounts, bundling PDUs with UPS and busway lines the entrant doesn't carry. The model prices incumbent response at exactly zero — no source quantifies it, and an unquantified competitive response is a risk, not a comfort. The reference-class outcome is win-rates and cycle times that pin Year-1 obtainable share at the 0.01 band floor rather than the 0.03 mid.",
 "category": "competitive",
 "targetNodes": [
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The entrant's first competitive bids surface in a field where 5–7 scaled incumbents each defend account share, and low-cost import supply anchors the price floor in the faster-growing eastern geographies",
   "refs": [
    "digest:cr3-vendors#c5",
    "digest:cr3-vendors#c6",
    "ledger:shape.cr3"
   ]
  },
  {
   "step": "propagation",
   "text": "Incumbents respond inside accounts with framework discounts and bundle pricing (PDU + UPS + containment), stretching the entrant's win rate and cycle length; SOM guidance itself says capture is a function of win-rate and conversion, and no cached source quantifies incumbent response — the model implicitly sets it to zero",
   "refs": [
    "digest:cr3-vendors#c1",
    "digest:obtainable-benchmark#c9",
    "ledger:obtainableFactor"
   ]
  },
  {
   "step": "model-impact",
   "text": "Depressed win-rate and stretched cycles convert the same pipeline into materially less Year-1 revenue: obtainableFactor lands at the 0.01 band floor, not the 0.03 mid-band the generic benchmarks suggest",
   "refs": [
    "ledger:obtainableFactor",
    "digest:obtainable-benchmark#c0"
   ]
  }
 ],
 "whyMissable": "'Medium concentration' reads as the friendly middle — enough fragmentation for an entrant to squeeze in. The surface label hides the mechanism: fragmentation among SCALED incumbents means more parties with amortized cert and channel costs able to price-match any niche the entrant opens, whereas a tight CR3 would at least leave uncontested edges.",
 "expectedObviousness": "medium",
 "falsifier": "Entrant win-rate ≥30% across the first 10 competitive CE bids in which an incumbent submitted a counter-offer, with no material price concession beyond plan.",
 "likelihood": {
  "value": 0.55,
  "rationale": "Base rate for new entrants into semi-consolidated industrial hardware categories: incumbent in-account price defense is near-universal, and the corpus documents both the multi-incumbent structure and the import price floor; the offset is that intelligent-PDU differentiation (firmware, telemetry) sometimes escapes pure price competition [evidence revision: Both structural premises (multi-incumbent 'medium' concentration and 60-70% import floor) are independently corroborated by multiple industry reports, strengthening the mechanism's trigger. Reference-class auction evidence supports depressed entrant survival. Modest upward revision from 0.5; retained near midpoint because the intelligent-PDU differentiation offset remains plausible (firmware/telemetry escapes pure price competition) and no source directly quantifies incumbent in-account response, so the leap to the 0.01 floor vs 0.03 mid remains partly inferential.]",
  "basis": "evidence",
  "revisedFrom": 0.5
 },
 "perturbation": [
  {
   "nodeId": "obtainableFactor",
   "op": "set",
   "value": 0.01,
   "note": "Contested-bid win-rates and stretched cycles pin Year-1 capture at the band floor"
  }
 ],
 "indicators": [
  {
   "signal": "Targeted rebate and promo activity on incumbent intelligent-PDU lines",
   "where": "Schneider/Vertiv/Eaton distributor price lists and channel rebate programs in Germany and the Netherlands",
   "threshold": "Targeted discounts >10% on intelligent-PDU SKUs appearing after the entrant's first public wins",
   "updates": "increases"
  },
  {
   "signal": "Loss-reason distribution in competitive bids",
   "where": "The venture's CRM bid post-mortems, reviewed quarterly",
   "threshold": ">50% of losses citing incumbent price match or bundle pricing",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Obtain the Omdia rack-PDU vendor-share table (2024 base) to establish which incumbents' share is actually contestable in CE and where the field is thinnest",
   "type": "information",
   "voiNodeId": "shape.cr3",
   "note": "Turns the extrapolated CR3 into a sourced map of contestable share before pipeline is committed"
  },
  {
   "action": "Position on an attribute the fragmented field cannot quickly price-match — e.g., firmware security certification, native DCIM/telemetry integration — and anchor pricing to that attribute rather than to the import floor",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Escapes the bundle-and-discount response pattern that kills price-positioned entrants"
  },
  {
   "action": "Lock a multi-year exclusive distribution agreement in one geography (e.g., Poland, where import dependence is highest) to secure a defended channel before incumbents respond",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Creates one protected revenue lane insensitive to in-account incumbent defense"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
